exercises.solution_code:
#include <iostream>
#include <string>

class Book {
public:
    std::string title;
    std::string author;
    int year{};

    void display() const {
        std::cout << '"' << title << '"' << " by " << author << " (" << year << ")\n";
    }
};

int main() {
    std::string title, author;
    int year;

    std::cin >> title >> author >> year;

    Book b{title, author, year};
    b.display();

    return 0;
}

