exercises.solution_code:
#include <iostream>

class Rectangle {
public:
    int width{};
    int height{};

    int area() const {
        return width * height;
    }

    int perimeter() const {
        return 2 * (width + height);
    }

    void display() const {
        std::cout << "Rectangle " << width << " x " << height
                  << ": area = " << area()
                  << ", perimeter = " << perimeter() << '\n';
    }
};

int main() {
    int n;
    std::cin >> n;

    for (int i = 0; i < n; ++i) {
        int w, h;
        std::cin >> w >> h;

        Rectangle r{w, h};
        r.display();
    }

    return 0;
}
